import stylesText from './day-meal-section.css?inline';
import { cssStyleSheet } from '../../../../utils/css.js';
import { createDayMealSectionAddEvent } from '../../health-events.js';

const styles = cssStyleSheet(stylesText);

const template = document.createElement('template');
template.innerHTML = `
    <section class="detail-section">
        <div class="section-header">
            <h3 data-role="title"></h3>
            <button class="add-mini-btn" data-role="add" type="button">+</button>
        </div>
        <div class="entries food-list">
            <slot></slot>
        </div>
    </section>
`;

/**
 * Presentation shell for a meal section in the day-detail view (Breakfast,
 * Lunch, Dinner, Snacks). Renders a header with the meal name and an "add"
 * button, plus a default `<slot>` for the parent to project entries into.
 * Emits a single `health:day-meal-section-add` event with the meal type —
 * the parent attaches date context.
 */
export class DayMealSection extends HTMLElement {
    static get observedAttributes() { return ['meal-type']; }

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        const addBtn = shadow.querySelector('[data-role="add"]') as HTMLButtonElement;
        addBtn.addEventListener('click', () => {
            this.dispatchEvent(createDayMealSectionAddEvent({ meal: this.getAttribute('meal-type') ?? '' }));
        });
    }

    attributeChangedCallback(name: string, _oldValue: string | null, newValue: string | null): void {
        if (name === 'meal-type' && this.shadowRoot) {
            const title = this.shadowRoot.querySelector('[data-role="title"]') as HTMLElement | null;
            const add = this.shadowRoot.querySelector('[data-role="add"]') as HTMLButtonElement | null;
            if (title) title.textContent = newValue ?? '';
            if (add) {
                add.title = newValue ? `Add ${newValue}` : 'Add';
                add.dataset.meal = newValue ?? '';
            }
        }
    }
}

if (!customElements.get('day-meal-section')) {
    customElements.define('day-meal-section', DayMealSection);
}
