import stylesText from './health-day-detail.css?inline';
import { cssStyleSheet } from '../../../utils/css.js';
import { formatMacro } from '../../../utils/format-macro.js';

const styles = cssStyleSheet(stylesText);
import { MEAL_TYPES } from '@motivation/shared';
import type { Activity, ConsumptionEntry, DailyNutritionSummary, FoodItem, Meal } from '@motivation/shared';
import {
    HEALTH_EVENTS,
    createAddWorkoutEvent,
    createAddFoodEvent,
    createEditWorkoutEvent,
    createEditFoodEvent,
} from '../health-events.js';
import type { DayMealSectionAddEvent, HealthEvent } from '../health-events.js';
import type { ActivityDetailCard } from './activity-detail-card.component.js';
import './activity-detail-card.component.js';
import './day-meal-section/day-meal-section.component.js';
import '../food-thumbnail/food-thumbnail.component.js';
import { FilesService } from '../../../services/files.service.js';
import { navigate } from '../../../router.js';

const template = document.createElement('template');
template.innerHTML = `
    <div class="day-detail-container">
        <header class="detail-header">
            <button class="nav-btn" id="prev-btn" title="Previous Day">←</button>
            <h2 id="day-title" class="date-title">Day Detail</h2>
            <button class="nav-btn" id="next-btn" title="Next Day">→</button>
        </header>

        <div id="selection-toolbar" class="selection-toolbar" hidden>
            <span id="selection-count" class="selection-count">0 selected</span>
            <button class="btn-primary" id="save-as-meal-btn" type="button" disabled>Save as Meal</button>
            <button class="btn-secondary" id="cancel-selection-btn" type="button">Cancel</button>
        </div>

        <div id="loading" class="loading" hidden>
            <div class="spinner"></div>
            <div>Loading data...</div>
        </div>

        <div id="error" class="error-banner" hidden></div>

        <div id="content" hidden>
            <section class="summary-card">
                <div class="summary-main">
                    <span class="cal-val" id="total-cal">0</span>
                    <span class="cal-unit">kcal total</span>
                </div>
                <div class="summary-macros">
                    <div class="macro-badge">Protein: <span id="total-p">0</span>g</div>
                    <div class="macro-badge">Carbs: <span id="total-c">0</span>g</div>
                    <div class="macro-badge">Fat: <span id="total-fat">0</span>g</div>
                    <div class="macro-badge">Fiber: <span id="total-fib">0</span>g</div>
                </div>
            </section>

            <section class="detail-section">
                <div class="section-header">
                    <h3>Workouts</h3>
                    <button class="add-mini-btn" id="add-workout-btn" title="Add Workout">+</button>
                </div>
                <div id="workouts-list">
                    <div class="empty-state">No workouts logged.</div>
                </div>
            </section>

            <div id="meal-sections"></div>
        </div>
    </div>
`;

const LONG_PRESS_MS = 500;
const LONG_PRESS_MOVE_TOLERANCE_PX = 10;

export class HealthDayDetail extends HTMLElement {
    private _dateStr: string = '';
    private _activities: Activity[] = [];
    private _nutrition: ConsumptionEntry[] = [];
    private _foodItemsById: Map<string, FoodItem> = new Map();
    private _mealsById: Map<string, Meal> = new Map();
    private _summary: DailyNutritionSummary | null = null;
    private _selectionMode = false;
    private _selectedIds = new Set<string>();

    constructor() {
        super();
        const shadow = this.attachShadow({ mode: 'open' });
        shadow.adoptedStyleSheets = [styles];
        shadow.appendChild(template.content.cloneNode(true));

        shadow.getElementById('prev-btn')!.addEventListener('click', () => {
            if (!this._dateStr) return;
            const prevDay = Temporal.PlainDate.from(this._dateStr).subtract({ days: 1 }).toString();
            navigate(`/health/day/${prevDay}`, { history: 'replace' });
        });

        shadow.getElementById('next-btn')!.addEventListener('click', () => {
            if (!this._dateStr) return;
            const nextDay = Temporal.PlainDate.from(this._dateStr).add({ days: 1 }).toString();
            navigate(`/health/day/${nextDay}`, { history: 'replace' });
        });

        shadow.getElementById('add-workout-btn')!.addEventListener('click', () => {
            if (!this._dateStr) return;
            this.dispatchEvent(createAddWorkoutEvent({ date: this._dateStr }));
        });

        shadow.getElementById('cancel-selection-btn')!.addEventListener('click', () => {
            this.exitSelectionMode();
        });

        shadow.getElementById('save-as-meal-btn')!.addEventListener('click', () => {
            if (this._selectedIds.size === 0) return;
            // Preserve user-visible order: filter the rendered nutrition list by selection.
            const ordered = this._nutrition
                .filter((e) => this._selectedIds.has(e.id))
                .map((e) => e.id);
            navigate(`/health/meals?fromSelection=${ordered.map(encodeURIComponent).join(',')}`);
        });

        const mealSections = shadow.getElementById('meal-sections')!;
        for (const meal of MEAL_TYPES) {
            const section = document.createElement('day-meal-section');
            section.setAttribute('meal-type', meal);
            section.dataset.mealType = meal;
            const emptyState = document.createElement('div');
            emptyState.className = 'empty-state';
            emptyState.dataset.role = 'empty';
            emptyState.textContent = 'Nothing logged yet.';
            section.appendChild(emptyState);
            mealSections.appendChild(section);
        }

        // Listen on the host rather than the shadow root: `ShadowRoot`'s typed
        // event map only knows `slotchange`, so the typed CustomEvent listener
        // doesn't type-check against shadow.addEventListener. Same outcome at
        // runtime because `day-meal-section-add` bubbles + composed.
        this.addEventListener(HEALTH_EVENTS.DAY_MEAL_SECTION_ADD, (event: DayMealSectionAddEvent) => {
            if (!this._dateStr) return;
            this.dispatchEvent(createAddFoodEvent({ date: this._dateStr, meal: event.detail.meal }));
        });
    }

    set dateContext(val: string) {
        if (val !== this._dateStr) this.exitSelectionMode();
        this._dateStr = val;
        this.shadowRoot!.getElementById('day-title')!.textContent = val;
    }

    get dateContext(): string {
        return this._dateStr;
    }

    set activities(data: Activity[]) {
        this._activities = data;
        this.renderWorkouts();
    }

    set nutrition(data: ConsumptionEntry[]) {
        this._nutrition = data;
        this.renderNutrition();
        this.renderSummary();
    }

    set foodItemsById(items: Map<string, FoodItem>) {
        this._foodItemsById = items;
        this.renderNutrition();
    }

    set mealsById(items: Map<string, Meal>) {
        this._mealsById = items;
        this.renderNutrition();
    }

    set summary(data: DailyNutritionSummary | null) {
        this._summary = data;
        this.renderSummary();
    }

    showLoading() {
        const shadow = this.shadowRoot!;
        shadow.getElementById('loading')!.hidden = false;
        shadow.getElementById('content')!.hidden = true;
        shadow.getElementById('error')!.hidden = true;
    }

    hideLoading() {
        this.shadowRoot!.getElementById('loading')!.hidden = true;
    }

    showError(message: string) {
        const shadow = this.shadowRoot!;
        const el = shadow.getElementById('error')!;
        el.textContent = message;
        el.hidden = false;
        shadow.getElementById('loading')!.hidden = true;
    }

    showContent() {
        this.shadowRoot!.getElementById('content')!.hidden = false;
    }

    private renderSummary() {
        const shadow = this.shadowRoot!;
        let cal = 0, p = 0, c = 0, f = 0, fib = 0;

        if (this._summary) {
            cal = this._summary.total_calories;
            p = this._summary.total_protein_g;
            c = this._summary.total_carbs_g;
            f = this._summary.total_fat_g;
            fib = this._summary.total_fiber_g;
        } else if (this._nutrition.length > 0) {
            // Fallback aggregation if summary not provided yet
            cal = this._nutrition.reduce((s, e) => s + (e.calories ?? 0), 0);
            p = this._nutrition.reduce((s, e) => s + (e.protein_g ?? 0), 0);
            c = this._nutrition.reduce((s, e) => s + (e.carbs_g ?? 0), 0);
            f = this._nutrition.reduce((s, e) => s + (e.fat_g ?? 0), 0);
            fib = this._nutrition.reduce((s, e) => s + (e.fiber_g ?? 0), 0);
        }

        shadow.getElementById('total-cal')!.textContent = formatMacro(cal);
        shadow.getElementById('total-p')!.textContent = formatMacro(p);
        shadow.getElementById('total-c')!.textContent = formatMacro(c);
        shadow.getElementById('total-fat')!.textContent = formatMacro(f);
        shadow.getElementById('total-fib')!.textContent = formatMacro(fib);
        
    }

    private renderWorkouts() {
        const container = this.shadowRoot!.getElementById('workouts-list')!;
        container.replaceChildren();
        if (this._activities.length === 0) {
            const emptyState = document.createElement('div');
            emptyState.className = 'empty-state';
            emptyState.textContent = 'No workouts logged.';
            container.appendChild(emptyState);
            return;
        }

        for (const act of this._activities) {
            const card = document.createElement('activity-detail-card') as ActivityDetailCard;
            card.activity = act;
            // Calendar activities are re-materialized live and have no DB row, so
            // editing/deleting them is meaningless — only manual + Strava cards are
            // clickable (the edit page then shows source-appropriate affordances).
            if (act.source !== 'calendar') {
                card.style.cursor = 'pointer';
                card.addEventListener('click', () => {
                    this.dispatchEvent(createEditWorkoutEvent({ activity: act }));
                });
            }
            container.appendChild(card);
        }
    }

    private renderNutrition() {
        const shadow = this.shadowRoot!;
        for (const meal of MEAL_TYPES) {
            const section = shadow.querySelector(`day-meal-section[data-meal-type="${meal}"]`) as HTMLElement | null;
            if (!section) continue;
            section.replaceChildren();

            const entries = this._nutrition.filter(e =>
                e.meal_type && e.meal_type.toLowerCase() === meal.toLowerCase()
            );

            if (entries.length === 0) {
                const emptyState = document.createElement('div');
                emptyState.className = 'empty-state';
                emptyState.textContent = 'Nothing logged yet.';
                section.appendChild(emptyState);
                continue;
            }

            // Group by meal_occurrence_id so entries logged from a meal template
            // collapse under one header. Entries without an occurrence id render flat.
            const grouped = new Map<string, ConsumptionEntry[]>();
            const ungrouped: ConsumptionEntry[] = [];
            for (const entry of entries) {
                const occurrenceId = entry.meal_occurrence_id;
                if (occurrenceId) {
                    const arr = grouped.get(occurrenceId) ?? [];
                    arr.push(entry);
                    grouped.set(occurrenceId, arr);
                } else {
                    ungrouped.push(entry);
                }
            }

            for (const [, groupEntries] of grouped) {
                section.appendChild(this.createMealGroup(groupEntries));
            }
            for (const entry of ungrouped) {
                section.appendChild(this.createFoodItem(entry));
            }
        }
    }

    private createMealGroup(entries: ConsumptionEntry[]): HTMLElement {
        const sourceMealId = entries[0]?.source_meal_id ?? null;
        const meal = sourceMealId ? this._mealsById.get(sourceMealId) ?? null : null;
        const mealName = meal?.name ?? null;
        const totalCal = entries.reduce((s, e) => s + (e.calories ?? 0), 0);

        const details = document.createElement('details');
        details.className = 'meal-group';
        if (meal?.image_path) details.classList.add('meal-group--with-banner');

        const summary = document.createElement('summary');
        summary.className = 'meal-group-summary';

        // Banner: <img> with darkening gradient overlay (CSS) so name/kcal stay
        // legible on arbitrary photos. The <img> is non-interactive (pointer-
        // events:none in CSS) so clicks fall through to the <summary> toggle.
        // Story 127.
        if (meal?.image_path) {
            const banner = document.createElement('img');
            banner.className = 'meal-group-banner';
            banner.src = FilesService.variantUrl(meal.image_path, 'display.jpg');
            banner.alt = '';
            banner.setAttribute('loading', 'lazy');
            banner.setAttribute('decoding', 'async');
            summary.appendChild(banner);
        }

        const nameSpan = document.createElement('span');
        nameSpan.className = 'meal-group-name';
        nameSpan.textContent = mealName ?? 'Deleted meal';
        const countSpan = document.createElement('span');
        countSpan.className = 'meal-group-count';
        countSpan.textContent = `${entries.length} item${entries.length === 1 ? '' : 's'}`;
        const calSpan = document.createElement('span');
        calSpan.className = 'food-cals';
        calSpan.textContent = `${formatMacro(totalCal)} kcal`;
        summary.appendChild(nameSpan);
        summary.appendChild(countSpan);
        summary.appendChild(calSpan);

        // Only meals that still have a template (source_meal_id is non-null) get
        // an edit link. Deleted-meal groups stay browse-only.
        if (sourceMealId) {
            const editLink = document.createElement('a');
            editLink.className = 'meal-group-edit';
            editLink.href = `/health/meals?focus=${encodeURIComponent(sourceMealId)}`;
            editLink.textContent = 'Edit recipe →';
            // Stop the click from bubbling to <summary>; otherwise it toggles open/close.
            editLink.addEventListener('click', (e) => e.stopPropagation());
            summary.appendChild(editLink);
        }

        details.appendChild(summary);

        for (const entry of entries) {
            details.appendChild(this.createFoodItem(entry));
        }
        return details;
    }

    private createFoodItem(entry: ConsumptionEntry): HTMLElement {
        const foodItem = this._foodItemsById.get(entry.food_item_id);
        const displayName = foodItem?.display_name ?? 'Unknown food';

        const item = document.createElement('div');
        item.className = 'food-item';
        item.dataset.entryId = entry.id;
        item.style.cursor = 'pointer';

        const checkbox = document.createElement('input');
        checkbox.type = 'checkbox';
        checkbox.className = 'food-select';
        checkbox.checked = this._selectedIds.has(entry.id);
        // Stop the checkbox from also triggering item-level click/long-press.
        checkbox.addEventListener('click', (e) => e.stopPropagation());
        checkbox.addEventListener('pointerdown', (e) => e.stopPropagation());
        checkbox.addEventListener('change', () => {
            if (checkbox.checked) this._selectedIds.add(entry.id);
            else this._selectedIds.delete(entry.id);
            this.refreshSelectionToolbar();
        });

        const thumb = document.createElement('food-thumb');
        if (foodItem?.image_path) thumb.setAttribute('path', foodItem.image_path);
        thumb.setAttribute('alt', displayName);

        const name = document.createElement('span');
        name.className = 'food-name';
        name.textContent = displayName;

        const cals = document.createElement('span');
        cals.className = 'food-cals';
        cals.textContent = `${formatMacro(entry.calories ?? 0)} kcal`;

        const macros = document.createElement('div');
        macros.className = 'food-macros';
        const chip = (label: string, value: number, unit: string): HTMLSpanElement => {
            const s = document.createElement('span');
            s.className = 'food-macro';
            s.textContent = `${label}:${formatMacro(value)}${unit}`;
            return s;
        };
        macros.append(
            chip('P', entry.protein_g ?? 0, 'g'),
            chip('C', entry.carbs_g ?? 0, 'g'),
            chip('F', entry.fat_g ?? 0, 'g'),
            chip('Fb', entry.fiber_g ?? 0, 'g'),
            chip('Sugar', entry.sugar_g ?? 0, 'g'),
            chip('Na', entry.sodium_mg ?? 0, 'mg'),
        );

        item.append(checkbox, thumb, name, cals, macros);
        this.attachEntryInteractions(item, entry);
        return item;
    }

    private attachEntryInteractions(item: HTMLElement, entry: ConsumptionEntry): void {
        let longPressTimer: ReturnType<typeof setTimeout> | null = null;
        let startX = 0;
        let startY = 0;
        let longPressed = false;

        const cancelTimer = () => {
            if (longPressTimer) {
                clearTimeout(longPressTimer);
                longPressTimer = null;
            }
        };

        item.addEventListener('pointerdown', (e) => {
            longPressed = false;
            startX = e.clientX;
            startY = e.clientY;
            cancelTimer();
            longPressTimer = setTimeout(() => {
                longPressTimer = null;
                longPressed = true;
                this.enterSelectionMode(entry.id);
                if (typeof navigator.vibrate === 'function') navigator.vibrate(10);
            }, LONG_PRESS_MS);
        });

        item.addEventListener('pointermove', (e) => {
            if (!longPressTimer) return;
            if (Math.hypot(e.clientX - startX, e.clientY - startY) > LONG_PRESS_MOVE_TOLERANCE_PX) {
                cancelTimer();
            }
        });

        item.addEventListener('pointerup', cancelTimer);
        item.addEventListener('pointercancel', cancelTimer);
        item.addEventListener('pointerleave', cancelTimer);

        // Suppress the native context menu the browser fires for long-press —
        // it would compete with our selection-mode trigger.
        item.addEventListener('contextmenu', (e) => e.preventDefault());

        item.addEventListener('click', (e) => {
            if (longPressed) {
                longPressed = false;
                e.preventDefault();
                e.stopPropagation();
                return;
            }
            if (this._selectionMode) {
                this.toggleSelection(entry.id);
                return;
            }
            this.dispatchEvent(createEditFoodEvent({ entry }));
        });
    }

    private enterSelectionMode(seedEntryId: string): void {
        this._selectionMode = true;
        this._selectedIds.add(seedEntryId);
        this.classList.add('selection-mode');
        // Reflect checkbox state on the seeded row (it is already in the DOM).
        this.syncCheckboxes();
        this.refreshSelectionToolbar();
    }

    private exitSelectionMode(): void {
        if (!this._selectionMode && this._selectedIds.size === 0) return;
        this._selectionMode = false;
        this._selectedIds.clear();
        this.classList.remove('selection-mode');
        this.syncCheckboxes();
        this.refreshSelectionToolbar();
    }

    private toggleSelection(entryId: string): void {
        if (this._selectedIds.has(entryId)) this._selectedIds.delete(entryId);
        else this._selectedIds.add(entryId);
        this.syncCheckboxes();
        this.refreshSelectionToolbar();
    }

    private syncCheckboxes(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const items = shadow.querySelectorAll<HTMLElement>('.food-item[data-entry-id]');
        for (const item of items) {
            const id = item.dataset.entryId!;
            const cb = item.querySelector<HTMLInputElement>('.food-select');
            if (cb) cb.checked = this._selectedIds.has(id);
        }
    }

    private refreshSelectionToolbar(): void {
        const shadow = this.shadowRoot;
        if (!shadow) return;
        const toolbar = shadow.getElementById('selection-toolbar')!;
        const count = shadow.getElementById('selection-count')!;
        const saveBtn = shadow.getElementById('save-as-meal-btn') as HTMLButtonElement;
        toolbar.hidden = !this._selectionMode;
        const n = this._selectedIds.size;
        count.textContent = `${n} selected`;
        saveBtn.disabled = n === 0;
    }

}

customElements.define('health-day-detail', HealthDayDetail);
